import React from 'react';
import RuShaktiLogo from './components/RuShaktiLogo';
import './App.css';

export default function App() {
  return (
    <div className="app">
      {/* Subtle background radial glow */}
      <div className="bg-glow" />

      <main className="hero">
        <RuShaktiLogo />
      </main>

      <footer className="site-footer">
        <p>Empowering Strength &bull; Inspiring Grace</p>
      </footer>
    </div>
  );
}
